ALTER TABLE "counter_bills" ADD CONSTRAINT "counter_bills_pharmacyId_fkey" FOREIGN KEY ("pharmacyId") REFERENCES "pharmacies"("id") ON DELETE CASCADE ON UPDATE CASCADE;
