ALTER TABLE "vendor_promotions" ADD CONSTRAINT "vendor_promotions_pharmacyId_fkey" FOREIGN KEY ("pharmacyId") REFERENCES "pharmacies"("id") ON DELETE CASCADE ON UPDATE CASCADE;
